var e=[{id:`L2_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`네가 왜… 그런 모습으로, 타기리온의 영역에 있는 거지?`,JPN:`そなたが何故……そのような姿で、タギリオンの領域にいるのだ？`,ENG:`Why... are you dressed like that and in Thagirion's lair?`,TWN:`你為什麼……以那副姿態，站在塔基里翁的領地？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`제가 아는 예하께선 누구보다 현명한 분이셨어요.`,JPN:`私が知っている猊下は誰よりも賢明な方でした。`,ENG:`The Eminence I knew was wiser than anyone else.`,TWN:`主教是我認識的人當中最賢明的一位。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`DOLL_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`그런 어리석은 질문을 되풀이하는 건 어울리지 않네요.`,JPN:`そんな愚かな質問を繰り返すのは似つかわしくありませんね。`,ENG:`It's not like you to be repeating such a foolish question.`,TWN:`反復提出如此愚蠢的問題很不像您。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`DOLL_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`실은 이미 알고 계시지 않나요?`,JPN:`もうお気づきですよね？`,ENG:`In truth, don't you already know?`,TWN:`其實您早就知道了不是嗎？`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`DOLL_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`저를… 어떻게 불러야 하는지도.`,JPN:`私を……どう呼ぶべきかも。`,ENG:`How... you should address me?`,TWN:`您也早就知道……如何稱呼我。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`DOLL_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`아니, 아니야!`,JPN:`違う、違う！`,ENG:`No, no!`,TWN:`不不，不不！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`네가 그런 선택을 할 리 없다!`,JPN:`そなたがそのような選択をするはずがない！`,ENG:`You would never choose to be like this!`,TWN:`你絕不會這麼做！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`MORS_SHADOW_CA_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`무섭게 소리를 지르시는군요.`,JPN:`恐ろしく怒鳴るんですね。`,ENG:`Your shouting is scaring me.`,TWN:`您叫得很嚇人。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`DOLL_NPC_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`QM_MARK_ANY_NOIMAGE`,text:{KOREA:`그때처럼.`,JPN:`あの時のように。`,ENG:`Just like that time.`,TWN:`就像那時一樣。`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`DOLL_NPC_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`아아…`,JPN:`ああ……`,ENG:`Ahh...`,TWN:`啊啊……`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`DOLL_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MORS_SHADOW_CA_NULL`,text:{KOREA:`아아아아아아!!!!!`,JPN:`ああああああ！！`,ENG:`AAAAGH!!!`,TWN:`啊啊啊啊啊！！！！！`},stage:{bg:`COUNTERSIDE_ASH`,slots:{L:null,C:{char_id:`DOLL_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:null,text:{KOREA:`멈출 기회는 얼마든지 있었다.`,JPN:`止める機会はいくらでもあった。`,ENG:`There were plenty of chances to stop.`,TWN:`曾經有很多機會停手。`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NAME`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`종말을 막겠다는 일념 하나에만 매몰되지 않았더라면…`,JPN:`終末を防ぐという一念に囚われていなかったら……`,ENG:`If only I had not been obsessed with the idea of preventing the end...`,TWN:`要不是一心只想著阻止末日……`},stage:{bg:`CHURCH`,slots:{L:null,C:{char_id:`CONDUCT_HARMONY_NULL_NAME`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:null,text:{KOREA:`나에겐 기회가 있었다.`,JPN:`我には機会があったのだ。`,ENG:`I had the opportunity.`,TWN:`我本來還有機會。`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`DASH_HORIZON_EX_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:null,text:{KOREA:`내가 내린 선택이 그릇될 수 있다는 사실을 인정했더라면…`,JPN:`我が下した決断が間違うこともあるということを認めたのならば……`,ENG:`If only I had accepted that my choices could have been wrong...`,TWN:`要是我承認我的選擇有可能是錯的。`},stage:{bg:`COUNTERSIDE_FOREST_NIGHT`,slots:{L:null,C:{char_id:`DASH_HORIZON_EX_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:null,text:{KOREA:`…소녀가 그토록 비참한 결말을 맞지는 않았으리라.`,JPN:`……あの少女があんな残酷な結末を迎えなくてもよかったのだろう。`,ENG:`…the child would not have met such a tragic ending.`,TWN:`……那麼她就不會落得如此悲慘的下場。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}}];export{e as default};